SELECT NTCART_SEQ ,SNS_CTG_CD ,YY ,MM ,SNS_CNTPNT_CD ,NTCART_TITLE ,THUMB_IMG_NM ,THUMB_IMG_DESC ,PC_LIST_IMG_NM ,PC_LIST_IMG_DESC ,MOBILE_LIST_IMG_NM ,MOBILE_LIST_IMG_DESC ,PC_LINK_URL ,MOBILE_LINK_URL ,NTCART_DATE ,HIT_CNT ,SORT_ODRG ,USE_YN ,PSTNG_START_DATE ,PSTNG_END_DATE ,CRET_IP ,CRET_DT ,CRET_ID ,AMD_IP ,AMD_DT ,AMD_ID FROM NMCP_SNS_BOARD_BAS WHERE USE_YN = 'Y' AND SNS_CTG_CD = #{snsCtgCd}
AND SNS_CNTPNT_CD = #{snsCntpntCd}
AND PSTNG_END_DATE > TO_CHAR(SYSDATE, 'YYYYMMDDHHMMSS') ORDER BY SORT_ODRG
